// Imperative usage
const sheetRef = useRef<BottomSheetRef>(null);
<Button onPress={() => sheetRef.current?.open()}>Open Sheet</Button>
<BottomSheet ref={sheetRef} onClose={() => {}}>
  <Text>Sheet content</Text>
</BottomSheet>

// Combined controlled + imperative — open via ref, close via state
const sheetRef = useRef<BottomSheetRef>(null);
const [open, setOpen] = useState(false);
<BottomSheet ref={sheetRef} visible={open} onClose={() => setOpen(false)}>
  <ShareOptions />
</BottomSheet>
